/**
 * Collect child nodes in declaration order.
 * Reads named child/optChild/list fields from the exhaustive schema.
 * Leaf nodes return [].
 */
export function getChildren(node: KSNode): KSNode[] {
  const fields = C[node.kind];
  if (!fields || fields.length === 0) return [];
  const result: KSNode[] = [];
  for (const f of fields) {
    const v = (node as any)[f];
    if (v == null) continue;
    if (Array.isArray(v)) {
      for (const item of v) if (item != null) result.push(item);
    } else {
      result.push(v);
    }
  }
  return result;
}

